        d = {node: float('inf') for node in range(n)}
        d[src] = 0
        pq = [(0, src)]
        while pq:
            dw, u = heapq.heappop(pq)
            if dw > d.get(u, float('inf')):
                continue
            if u not in adj:
                continue
            for v, w in adj[u].items():
                nd = dw + w
                if nd < d.get(v, float('inf')):
                    d[v] = nd
                    heapq.heappush(pq, (nd, v))
