from typing import List, Tuple

def k_shortest_paths(n: int, edges: List[Tuple[int, int, float]], src: int, dst: int, k: int) -> List[float]:
    """
    Find the k shortest path lengths from src to dst in a weighted directed graph.

    Uses a modified Dijkstra where each node can be relaxed up to k times.
    Returns a sorted list of path lengths (up to k entries).
    """
    if n == 0 or not edges:
        return []
    if src < 0 or src >= n or dst < 0 or dst >= n:
        return []

    # Build adjacency list
    graph = [[] for _ in range(n)]
    for u, v, w in edges:
        if 0 <= u < n and 0 <= v < n and w >= 0:
            graph[u].append((v, w))

    if src not in range(n) or dst not in range(n):
        return []

    # Each node can be visited up to k times
    visited = [0] * n  # count of times each node has been finalized
    pq = [(0, src)]  # (distance, node)
    paths = []

    while pq and len(paths) < k:
        dist, u = heapq.heappop(pq)
        if visited[u] >= k:
            continue
        visited[u] += 1
        if visited[u] == 1:
            # First time reaching dst with this path
            if u == dst and len(paths) < k:
                paths.append(dist)
                heapq.heappush(pq, (dist, dst))  # Keep in PQ for potential shorter paths
            if u == dst and visited[u] > 1 and len(paths) < k:
                paths.append(dist)
                heapq.heappush(pq, (dist, dst))
        for v, w in graph[u]:
            if visited[v] <= k:
                heapq.heappush(pq, (dist + w, v))

    # Sort paths and return up to k
    paths.sort()
    return paths[:k]

