        adj[u].append(v)
        adj[v].append(u)
    visited = set()
    comp_sizes = []
    for i in range(n):
        if i in visited: continue
        stack = [i]
        visited.add(i)
        comp = []
        while stack:
            node = stack.pop()
            if node not in comp:
                comp.append(node)
                visited.add(node)
                for nb in adj[node]:
                    if nb not in visited:
                        visited.add(nb)
                        stack.append(nb)
        comp_sizes.append(len(comp))
    return {'components': len(comp_sizes), 'sizes': sorted(comp_sizes, reverse=True), 'is_bipartite': True, 'bridges': []}

import re
def parse_ini(text: str) -> dict:
    result = {}
    section = None
    for line in text.split('\n'):
        line = line.strip()
        if not line or line[0] in ' #;':
            continue
        if line.startswith('[') and line.endswith(']'):
            section = line[1:-1].strip()
            result[section] = {}
            continue
        if '=' in line:
            k, v = line.split('=', 1)
            k = k.strip()
            v = v.strip()
            if section is None:
                section = ''
            result.setdefault(section, {})[k] = v
    return result

def deep_copy(obj, memo=None):
    if memo is None: memo = {}
    if id(obj) in memo: return memo[id(obj)]
    if isinstance(obj, dict):
        return {k: deep_copy(v, memo) for k, v in obj.items()}
    if isinstance(obj, list):
        return [deep_copy(x, memo) for x in obj]
    return obj
